"use client";

/**
 * <TrendSpark> — Tier-2 area-spark with milled nodes + end-value label.
 *
 * Step up from the bare <SparkLine> primitive: paints the area, draws square
 * nodes at each point, and pins the trailing value next to the last node.
 * Used for category cards and similar in-row sparks.
 *
 * Conforms to CHART-STANDARD §2: viewBox === real px width via useChartSize.
 */

import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface TrendSparkProps {
  data?: number[];
  color: string;
  /** Formatter for the trailing end-label, e.g. (v) => `${v.toFixed(1)}%` */
  fmt: (v: number) => string;
  state?: ChartState;
  /** SVG height in px. Drives the intrinsic ratio. */
  height?: number;
  /** Reserve room at the right for the end-value label. */
  rightPadPx?: number;
  /** Stroke width for the line. */
  strokeWidth?: number;
  /** Label used in empty/error copy. */
  label?: string;
}

export const sampleTrendSparkData: number[] = [
  17.2, 17.6, 17.4, 18.1, 18.5, 19.6, 19.7,
];

export function TrendSpark({
  data = sampleTrendSparkData,
  color,
  fmt,
  state = "ready",
  height = 64,
  rightPadPx = 56,
  strokeWidth = 2.6,
  label = "Trend",
}: TrendSparkProps) {
  const { ref, width } = useChartSize({ min: 220, fallback: 420 });
  const W = Math.max(220, width);
  const H = height;
  const padT = 12;
  const padB = 12;
  const padL = 2;
  const padR = rightPadPx;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;

  if (data.length < 2 && state === "ready") state = "empty";

  const min = data.length ? Math.min(...data) : 0;
  const max = data.length ? Math.max(...data) : 1;
  const span = max - min || 1;
  const x = (i: number) =>
    padL + (i / Math.max(1, data.length - 1)) * plotW;
  const y = (v: number) => padT + (1 - (v - min) / span) * plotH;
  const pts = data.map((v, i) => ({ x: x(i), y: y(v) }));
  const linePath = pts
    .map((p, i) => (i ? "L" : "M") + p.x.toFixed(1) + " " + p.y.toFixed(1))
    .join(" ");
  const areaPath = pts.length
    ? linePath +
      ` L ${pts[pts.length - 1].x.toFixed(1)} ${padT + plotH} L ${pts[0].x.toFixed(1)} ${padT + plotH} Z`
    : "";
  const last = pts[pts.length - 1];
  const lastVal = data[data.length - 1];
  const gid = `trend-${color.replace(/[^a-zA-Z0-9]/g, "")}`;

  return (
    <div ref={ref} style={{ width: "100%", height }}>
      <ChartStates state={state} height={height} label={label}>
        <svg
          className="trend-spark"
          viewBox={`0 0 ${W} ${H}`}
          style={{ display: "block", width: "100%", height: `${H}px` }}
        >
          <defs>
            <linearGradient id={gid} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" stopColor={color} stopOpacity="0.15" />
              <stop offset="1" stopColor={color} stopOpacity="0" />
            </linearGradient>
          </defs>
          {areaPath && <path d={areaPath} fill={`url(#${gid})`} />}
          <path
            d={linePath}
            fill="none"
            stroke={color}
            strokeWidth={strokeWidth}
            strokeLinecap="round"
            strokeLinejoin="round"
          />
          {pts.slice(0, -1).map((p, i) => (
            <rect
              key={i}
              x={p.x - 2.6}
              y={p.y - 2.6}
              width={5.2}
              height={5.2}
              fill="#fff"
              stroke={color}
              strokeWidth={1.4}
            />
          ))}
          {last && (
            <>
              <rect
                x={last.x - 3.4}
                y={last.y - 3.4}
                width={6.8}
                height={6.8}
                rx={1}
                fill={color}
                stroke="#fff"
                strokeWidth={1.4}
              />
              <text
                x={last.x + 8}
                y={last.y + 4}
                fontSize="12.5"
                fill={color}
                fontWeight="600"
              >
                {fmt(lastVal)}
              </text>
            </>
          )}
        </svg>
      </ChartStates>
    </div>
  );
}
