"use client";

import Link from "next/link";
import { useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { TrendSpark } from "@/components/charts/TrendSpark";
import {
  CATEGORIES,
  costMetrics,
  costCategoriesAI,
  type CostCategory,
} from "@/features/finance/api/finance-cost-categories-data";
import "./categories.css";

const PERIOD_LABELS = ["Last 90 days", "Last 6 months", "Last 12 months", "Year to date"];
export default function CategoriesPage() {
  const [periodIdx, setPeriodIdx] = useState(1);

  return (
    <div className="finance-categories-page">
      <DeptHeader
        dept="finance"
        title="Cost Categories"
        meta={
          <>
            <span className="live">Live</span> · Where money goes by category, and the trend · from ledger
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Add category →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Total spend (MTD)</div>
          <div className="metric-v">{costMetrics.totalMTD}</div>
          <div className="metric-s up">{costMetrics.totalDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Fixed</div>
          <div className="metric-v">{costMetrics.fixed}</div>
          <div className="metric-s">{costMetrics.fixedShare}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Variable</div>
          <div className="metric-v">{costMetrics.variable}</div>
          <div className="metric-s">{costMetrics.variableShare}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Largest category</div>
          <div className="metric-v">{costMetrics.largest}</div>
          <div className="metric-s">{costMetrics.largestShare}</div>
        </div>
      </div>

      <AIStrip
        label={costCategoriesAI.label}
        meta={costCategoriesAI.meta}
        cards={costCategoriesAI.cards}
      />

      {/* Category grid */}
      <SectionLabel>By category — spend, trend, and whether it&rsquo;s healthy</SectionLabel>
      <div className="cat-grid">
        {CATEGORIES.map((c: CostCategory) => (
          <Link key={c.id} href={`/finance/categories/${c.id}`} className="ccard">
            <div className="cc-top">
              <div className="cc-name">
                <span className="dot" style={{ background: c.color }} />
                {c.name}
              </div>
              <span className={`cc-tag ${c.tag}`}>
                {c.tag === "var" ? "Variable" : "Fixed"}
              </span>
            </div>
            <div className="cc-spend">
              {c.spend}
              <span className="txn">{c.txns}</span>
            </div>
            <div className="cc-spark-wrap">
              <TrendSpark
                data={c.pctSeries}
                color={c.color}
                fmt={(v) => `${v.toFixed(1)}%`}
              />
            </div>
            <div className="cc-line" dangerouslySetInnerHTML={{ __html: c.line }} />
          </Link>
        ))}
      </div>

      <div className="bench-note">
        <span className="ic">i</span>
        <span>
          Each category is judged against <b>its own history</b>, not an industry average — a cost climbing against where it used to sit is the signal that matters. The percentages and trends here are measured from your ledger.
        </span>
      </div>
    </div>
  );
}
