/**
 * Mock data for Finance · Cost Categories (overview + detail).
 *
 * Each category carries:
 *   - 6-month % of revenue series (the trend the room cares about)
 *   - 6-month dollar series (the same story in $)
 *   - own-history benchmark range (judged against itself, not industry avg)
 *   - drill rows showing what drives the category
 *   - cause/argument prose for the room voice
 */

export type CategoryTag = "fix" | "var";
export type CategoryVerdict = "ok" | "watch" | "alert";
export type CategoryTrend = "up" | "down" | "flat";

export interface CatDrillRow {
  name: string;
  meta: string;
  amount: string;
  changePct: string;
  changeClass: "up" | "down" | "flat";
  /** bar width 0-100 (proportional) */
  bar: number;
}

export interface CostCategory {
  id: string;
  name: string;
  tag: CategoryTag;
  /** brand color */
  color: string;
  spend: string;
  txns: string;
  pctSeries: number[]; // 6 months, oldest → newest
  dolSeries: number[]; // 6 months, in thousands
  benchLow: number;
  benchHigh: number;
  now: number;
  prev: number;
  verdict: CategoryVerdict;
  trend: CategoryTrend;
  /** short line under the spark on the overview card */
  line: string;
  /** longer prose for the detail page hero argument */
  arg: string;
  /** detail-page "cause" prose */
  cause: string;
  drill: CatDrillRow[];
}

